fn clear_bss() {
    unsafe extern "C" {
        safe fn sbss();
        safe fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(sbss as usize as *mut u8, ebss as usize - sbss as usize)
            .fill(0);
    }
}

use lazy_static::*;
use sync::UPIntrFreeCell;

static BOOT_HART_ID: AtomicUsize = AtomicUsize::new(0);
static DTB_ADDR: AtomicUsize = AtomicUsize::new(0);

lazy_static! {
    pub static ref DEV_NON_BLOCKING_ACCESS: UPIntrFreeCell<bool> =
        unsafe { UPIntrFreeCell::new(false) };
}

#[unsafe(no_mangle)]
pub extern "C" fn rust_main(hart_id: usize, dtb_addr: usize) -> ! {
    clear_bss();
    BOOT_HART_ID.store(hart_id, Ordering::Relaxed);
    DTB_ADDR.store(dtb_addr, Ordering::Relaxed);
    board::init_from_dtb(dtb_addr);
    mm::init();
    timer::init_wall_clock();
    UART.init();
    logging::init();
    info!("boot hart_id={hart_id}, dtb_addr={dtb_addr:#x}");
    info!(
        "board config: clock_freq={}, memory_end={:#x}, uart={:#x}, plic={:#x}",
        board::clock_freq(),
        board::memory_end(),
        board::uart_base(),
        board::plic_base(),
    );

    // CONTEXT: Headless contest QEMU may omit these optional devices, but
    // smoke checks key on the unavailable-device log lines below.
    if board::gpu_device().is_some() {
        info!("KERN: init gpu");
    } else {
        info!("KERN: gpu device unavailable");
    }

    if let Some(_keyboard) = KEYBOARD_DEVICE.as_ref() {
        info!("KERN: init keyboard");
    } else {
        info!("KERN: keyboard device unavailable");
    }

    if let Some(_mouse) = MOUSE_DEVICE.as_ref() {
        info!("KERN: init mouse");
    } else {
        info!("KERN: mouse device unavailable");
    }

    info!("KERN: init trap");
    trap::init();
    trap::enable_timer_interrupt();
    timer::set_next_trigger();
    board::device_init(hart_id);
    fs::init();
    fs::list_apps();
    task::add_initproc();
    // CONTEXT: Task-context block I/O can use the nonblocking path only after
    // the active architecture has wired device IRQ completion. The driver still
    // falls back to sync I/O when a read happens from an unsafe context such as
    // interrupt-disabled lazy fault-in.
    *DEV_NON_BLOCKING_ACCESS.exclusive_access() = board::block_irq_available();
    task::run_tasks();
    panic!("Unreachable in rust_main!");
}

// Static contest layout limits. Changing these affects loader stack layout,
// mmap placement, trampoline/trap-context spacing, and address-space tests.
pub const USER_STACK_SIZE: usize = 4096 * 1024;
pub const USER_HEAP_SIZE: usize = 0x20_0000;
pub const USER_MMAP_BASE: usize = 0x6000_0000;
pub const USER_MMAP_LIMIT: usize = 0x20_0000_0000;
pub const DL_INTERP_OFFSET: usize = 0x30_0000_0000;
pub const KERNEL_STACK_SIZE: usize = 4096 * 10;

pub const KERNEL_HEAP_SIZE: usize = 0x800_0000;

pub const PAGE_SIZE: usize = 0x1000;
pub const PAGE_SIZE_BITS: usize = 0xc;

pub const TRAMPOLINE: usize = usize::MAX - PAGE_SIZE + 1;
pub const TRAP_CONTEXT_BASE: usize = TRAMPOLINE - PAGE_SIZE;

pub fn clock_freq() -> usize {
    crate::board::clock_freq()
}

pub fn memory_end() -> usize {
    crate::board::memory_end()
}

pub fn mmio_regions() -> &'static [crate::board::MmioRange] {
    crate::board::mmio_regions()
}

OUTPUT_ARCH(riscv)
ENTRY(_start)
BASE_ADDRESS = 0x80200000;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    stext = .;
    .text : {
        *(.text.entry)
        . = ALIGN(4K);
        strampoline = .;
        *(.text.trampoline);
        . = ALIGN(4K);
        *(.text .text.*)
    }

    . = ALIGN(4K);
    etext = .;
    srodata = .;
    .rodata : {
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
    }

    . = ALIGN(4K);
    erodata = .;
    sdata = .;
    .data : {
        *(.data .data.*)
        *(.sdata .sdata.*)
    }

    . = ALIGN(4K);
    edata = .;
    sbss_with_stack = .;
    .bss : {
        *(.bss.stack)
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
    }

    . = ALIGN(4K);
    ebss = .;
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
    }
}

