    BOARD_CONFIG.get()
}

fn compatible_contains(node: FdtNode<'_, '_>, compatibles: &[&str]) -> bool {
    node.compatible()
        .map(|node_compatibles| {
            node_compatibles
                .all()
                .any(|name| compatibles.contains(&name))
        })
        .unwrap_or(false)
}

fn property_str<'a>(node: FdtNode<'_, 'a>, name: &str) -> Option<&'a str> {
    node.property(name)
        .and_then(|property| core::str::from_utf8(property.value).ok())
        .map(|value| value.trim_end_matches('\0'))
}

fn first_reg(node: FdtNode<'_, '_>, context: &str) -> MmioRange {
    let region = node
        .reg()
        .and_then(|mut regions| regions.next())
        .unwrap_or_else(|| panic!("{} node is missing a usable reg property", context));

    MmioRange {
        base: region.starting_address as usize,
        size: region
            .size
            .unwrap_or_else(|| panic!("{} node reg is missing size", context)),
    }
}

fn irq_device(node: FdtNode<'_, '_>, context: &str) -> IrqDevice {
    let range = first_reg(node, context);
    let irq = node
        .interrupts()
        .and_then(|mut interrupts| interrupts.next())
        .unwrap_or_else(|| panic!("{} node is missing an interrupts property", context));

    IrqDevice {
        base: range.base,
        size: range.size,
        irq,
    }
}

fn push_mmio_region(config: &mut BoardConfig, range: MmioRange) {
    assert!(
        config.mmio_region_count < config.mmio_regions.len(),
        "too many MMIO regions discovered in DTB"
    );
    config.mmio_regions[config.mmio_region_count] = range;

use core::arch::asm;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use riscv::register::satp;

const SV39_MODE: usize = 8;
const SATP_ASID_SHIFT: usize = 44;
const SATP_ASID_BITS: usize = 16;
const SATP_ASID_MAX: usize = (1usize << SATP_ASID_BITS) - 1;
const SATP_ASID_MASK: usize = SATP_ASID_MAX << SATP_ASID_SHIFT;
const SATP_PPN_MASK: usize = (1usize << 44) - 1;
const PA_WIDTH: usize = 56;
const VA_WIDTH: usize = 39;
const PPN_WIDTH: usize = PA_WIDTH - crate::config::PAGE_SIZE_BITS;
const VPN_WIDTH: usize = VA_WIDTH - crate::config::PAGE_SIZE_BITS;

const ASID_SUPPORT_NO: usize = 0;
const ASID_SUPPORT_YES: usize = 1;
const ASID_SUPPORT_UNKNOWN: usize = 2;

// ASID allocation starts at 1. On wrap, the allocator globally fences before
// reusing tag 1 so stale per-address-space TLB entries cannot survive under a
// recycled ASID.
static NEXT_ASID: AtomicUsize = AtomicUsize::new(1);
static ASID_SUPPORT: AtomicUsize = AtomicUsize::new(ASID_SUPPORT_UNKNOWN);
static LAST_RETURN_USER_TOKEN: AtomicUsize = AtomicUsize::new(0);
static LAST_ENTRY_KERNEL_TOKEN: AtomicUsize = AtomicUsize::new(0);
static RETURN_TLB_DIRTY: AtomicBool = AtomicBool::new(true);
static KERNEL_TLB_DIRTY: AtomicBool = AtomicBool::new(true);

pub fn page_table_token_with_asid(root_ppn: usize, asid: usize) -> usize {
    SV39_MODE << 60 | ((asid & SATP_ASID_MAX) << SATP_ASID_SHIFT) | (root_ppn & SATP_PPN_MASK)
}

pub fn page_table_root_ppn(token: usize) -> usize {
    token & SATP_PPN_MASK
}

pub fn page_table_asid(token: usize) -> usize {
    (token & SATP_ASID_MASK) >> SATP_ASID_SHIFT
}

pub fn alloc_page_table_asid() -> usize {
    let asid = NEXT_ASID.fetch_add(1, Ordering::Relaxed);
    if asid == 0 || asid > SATP_ASID_MAX {
        NEXT_ASID.store(2, Ordering::Relaxed);
        mark_return_tlb_dirty();
        unsafe {
            asm!("sfence.vma");
        }
        1
    } else {
        asid
    }
}

pub fn activate_page_table(token: usize) {
    satp::write(token);
    flush_tlb_all();
}

pub fn flush_tlb_all() {
    mark_return_tlb_dirty();
    unsafe {
        asm!("sfence.vma");
    }
}

pub fn flush_tlb_page(va: usize) {
    mark_return_tlb_dirty();
    unsafe {
        asm!("sfence.vma {va}, x0", va = in(reg) va);
    }
}

pub fn should_flush_tlb_on_return(user_token: usize) -> bool {
    if !asid_supported() {
        return true;
    }
    let previous = LAST_RETURN_USER_TOKEN.swap(user_token, Ordering::Relaxed);
    let dirty = RETURN_TLB_DIRTY.swap(false, Ordering::Relaxed);
    previous != user_token || dirty
}

pub fn should_flush_tlb_on_kernel_entry(kernel_token: usize) -> bool {
    if !asid_supported() {
        return true;
    }
    let previous = LAST_ENTRY_KERNEL_TOKEN.swap(kernel_token, Ordering::Relaxed);
    let dirty = KERNEL_TLB_DIRTY.swap(false, Ordering::Relaxed);
    previous != kernel_token || dirty
}

pub fn mark_kernel_tlb_dirty() {
    KERNEL_TLB_DIRTY.store(true, Ordering::Relaxed);
}

fn mark_return_tlb_dirty() {
    RETURN_TLB_DIRTY.store(true, Ordering::Relaxed);
}

fn asid_supported() -> bool {
    match ASID_SUPPORT.load(Ordering::Relaxed) {
        ASID_SUPPORT_YES => true,
        ASID_SUPPORT_NO => false,
        _ => probe_asid_supported(),
    }
}

fn probe_asid_supported() -> bool {
    let current = read_satp_bits();
    let probe = (current & !SATP_ASID_MASK) | SATP_ASID_MASK;
    write_satp_bits(probe);
    let observed = read_satp_bits();
    write_satp_bits(current);
    unsafe {
        asm!("sfence.vma");
    }
    let supported = observed & SATP_ASID_MASK != 0;
    ASID_SUPPORT.store(
        if supported {
            ASID_SUPPORT_YES
        } else {
            ASID_SUPPORT_NO
        },
        Ordering::Relaxed,
    );
    supported
}

fn read_satp_bits() -> usize {
    let bits: usize;
    unsafe {
        asm!("csrr {bits}, satp", bits = out(reg) bits, options(nomem, nostack));
    }
    bits
}

fn write_satp_bits(bits: usize) {
    unsafe {
        asm!("csrw satp, {bits}", bits = in(reg) bits, options(nomem, nostack));
    }
}

pub fn publish_pte_barrier() {}

pub fn instruction_barrier() {
    crate::perf::record_arch_instruction_barrier_call();
    unsafe {
        asm!("fence.i");
    }
}

pub fn canonicalize_phys_addr(addr: usize) -> usize {
    addr & ((1usize << PA_WIDTH) - 1)
}

pub fn canonicalize_phys_page_num(ppn: usize) -> usize {
    ppn & ((1usize << PPN_WIDTH) - 1)
}

pub fn canonicalize_virt_addr(addr: usize) -> usize {
    addr & ((1usize << VA_WIDTH) - 1)
}

pub fn canonicalize_virt_page_num(vpn: usize) -> usize {
    vpn & ((1usize << VPN_WIDTH) - 1)
}

pub fn sign_extend_virt_addr(addr: usize) -> usize {
    if addr >= (1usize << (VA_WIDTH - 1)) {
        addr | (!((1usize << VA_WIDTH) - 1))
    } else {
        addr
    }
}

pub fn phys_to_virt(addr: usize) -> usize {
    addr
}

pub fn pte_new_bits(ppn: usize, flags: crate::mm::page_table::PTEFlags) -> usize {
    ppn << 10 | flags.bits()
}

pub fn pte_ppn(bits: usize) -> usize {
    bits >> 10 & ((1usize << PPN_WIDTH) - 1)
}

pub fn pte_flags(bits: usize) -> crate::mm::page_table::PTEFlags {
    crate::mm::page_table::PTEFlags::from_bits_truncate(bits)
}

pub fn pte_is_valid(bits: usize) -> bool {
    pte_flags(bits).contains(crate::mm::page_table::PTEFlags::V)
}

use core::arch::asm;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

pub const VIRT_ADDR_START: usize = 0x9000_0000_0000_0000;
const DIRECT_MAP_MASK: usize = 0xf000_0000_0000_0000;
const PHYS_ADDR_MASK: usize = 0x0000_ffff_ffff_ffff;
const PTE_ADDR_MASK: usize = 0x0000_ffff_ffff_f000;
const LA_CSR_PGDL: usize = 0x19;
const LA_CSR_PGDH: usize = 0x1a;
const PA_WIDTH: usize = 48;
const VA_WIDTH: usize = 48;
const PPN_WIDTH: usize = PA_WIDTH - crate::config::PAGE_SIZE_BITS;
const VPN_WIDTH: usize = VA_WIDTH - crate::config::PAGE_SIZE_BITS;

const LA_PTE_V: usize = 1 << 0;
const LA_PTE_D: usize = 1 << 1;
const LA_PTE_PLV_USER: usize = 0b11 << 2;
const LA_PTE_MAT_CC: usize = 0b01 << 4;
const LA_PTE_P: usize = 1 << 7;
const LA_PTE_W: usize = 1 << 8;
const LA_PTE_COW: usize = 1 << 58;
// LA64 leaf PTEs encode read/execute denial as NR/NX; absence of those bits
// means read or execute permission is allowed.
const LA_PTE_NR: usize = 1 << 61;
const LA_PTE_NX: usize = 1 << 62;

static LAST_RETURN_USER_TOKEN: AtomicUsize = AtomicUsize::new(0);
static RETURN_TLB_DIRTY: AtomicBool = AtomicBool::new(true);

pub fn page_table_token(root_ppn: usize) -> usize {
    root_ppn << crate::config::PAGE_SIZE_BITS
}

pub fn page_table_token_with_asid(root_ppn: usize, _asid: usize) -> usize {
    page_table_token(root_ppn)
}

pub fn page_table_root_ppn(token: usize) -> usize {
    token >> crate::config::PAGE_SIZE_BITS
}

pub fn page_table_asid(_token: usize) -> usize {
    0
}

pub fn alloc_page_table_asid() -> usize {
    0
}

pub fn activate_page_table(token: usize) {
    // CONTEXT: The current LA64 port installs one MemorySet root into both
    // PGDL and PGDH. Splitting low/high roots requires auditing trap.S, the
    // refill entry, and direct-map address translation together.
    write_page_table_roots(token, token);
    flush_tlb_all();
}

fn write_page_table_roots(pgdl_token: usize, pgdh_token: usize) {
    unsafe {
        asm!(
            "csrwr {pgdl}, {pgdl_csr}",
            "csrwr {pgdh}, {pgdh_csr}",
            pgdl = inout(reg) pgdl_token => _,
            pgdh = inout(reg) pgdh_token => _,
            pgdl_csr = const LA_CSR_PGDL,
            pgdh_csr = const LA_CSR_PGDH,
            options(nomem, nostack),
        );
    }
}

pub fn flush_tlb_all() {
    mark_return_tlb_dirty();
    unsafe {
        asm!("dbar 0", "invtlb 0x00, $r0, $r0");
    }
}

pub fn flush_tlb_page(va: usize) {
    mark_return_tlb_dirty();
    unsafe {
        asm!("dbar 0", "invtlb 0x05, $r0, {va}", va = in(reg) va);
    }
}

pub fn should_flush_tlb_on_return(user_token: usize) -> bool {
    // The current LA64 path has no ASID allocation, so returning to a different
    // page-table root or after any PTE edit must request a guest TLB flush.
    let previous = LAST_RETURN_USER_TOKEN.swap(user_token, Ordering::Relaxed);
    let dirty = RETURN_TLB_DIRTY.swap(false, Ordering::Relaxed);
    previous != user_token || dirty
