    fn cmp(&self, other: &Self) -> Ordering {
        other
            .expire_us
            .cmp(&self.expire_us)
            .then_with(|| other.generation.cmp(&self.generation))
            .then_with(|| other.timer_id.cmp(&self.timer_id))
    }
}

