// Soft cap for ordinary read(2) cache pages. MAP_SHARED mmap pages are pinned
// and dirty-tracked separately, so this cap must not evict them.
pub(crate) const PAGE_CACHE_SOFT_MAX_PAGES: usize = 4096;

#[derive(Clone, Copy, Debug, Eq, PartialEq, Ord, PartialOrd)]
pub(crate) struct PageCacheId {
    pub(crate) mount_id: MountId,
    pub(crate) ino: u32,
}

impl PageCacheId {
    pub(crate) fn new(mount_id: MountId, ino: u32) -> Self {
        Self { mount_id, ino }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq, Ord, PartialOrd)]
pub(crate) struct PageCacheKey {
    pub(crate) id: PageCacheId,
    pub(crate) page_index: usize,
}

impl PageCacheKey {
    /// Builds a cache key only for page-aligned file offsets.
    ///
    /// The current mmap path caches full file pages; partial-page offsets fall
    /// back to private fault frames.
    pub(crate) fn from_file_offset(id: PageCacheId, file_offset: usize) -> Option<Self> {
        if file_offset % PAGE_SIZE != 0 {
            return None;
        }
        Some(Self {
            id,
            page_index: file_offset / PAGE_SIZE,
        })
    }

    /// Returns the byte offset represented by this file page key.
    pub(crate) fn file_offset(self) -> usize {
        self.page_index * PAGE_SIZE
    }
}

pub(crate) struct PageCachePage {
    pub(crate) frame: FrameTracker,
    pub(crate) key: PageCacheKey,
    // Size observed when this page was loaded; callers pass the mmap snapshot
    // that already bounded fault-time EOF reads before insertion.
    pub(crate) file_size_at_load: usize,
    // Dirty pages belong to MAP_SHARED writeback and are not soft-LRU victims.
    pub(crate) dirty: bool,
    // Active page-table mappings, not Arc references. Nonzero pins the frame.
    pub(crate) ref_count: usize,
    exec_icache_synced: bool,
    lru_stamp: usize,
}

impl PageCachePage {
    pub(crate) fn new(frame: FrameTracker, key: PageCacheKey, file_size_at_load: usize) -> Self {
        Self {
            frame,
            key,
            file_size_at_load,
            dirty: false,
            ref_count: 0,
            exec_icache_synced: false,
            lru_stamp: 0,
        }
    }

    pub(crate) fn ppn(&self) -> PhysPageNum {
        self.frame.ppn
    }

    fn ensure_exec_icache_synced(&mut self) {
        if self.exec_icache_synced {
            return;
        }
        crate::arch::mm::publish_pte_barrier();
        crate::arch::mm::instruction_barrier();
        self.exec_icache_synced = true;
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq, Ord, PartialOrd)]
struct PageCacheLruEntry {
    stamp: usize,
    key: PageCacheKey,
}

use crate::config::KERNEL_HEAP_SIZE;
use buddy_system_allocator::LockedHeap;
use core::alloc::{GlobalAlloc, Layout};
use core::ptr::addr_of_mut;

#[global_allocator]
static HEAP_ALLOCATOR: InterruptFreeLockedHeap<32> = InterruptFreeLockedHeap::empty();

struct InterruptGuard {
    enabled_before: bool,
}

impl InterruptGuard {
    fn new() -> Self {
        let enabled_before = crate::arch::interrupt::supervisor_interrupt_enabled();
        crate::arch::interrupt::disable_supervisor_interrupt();
        Self { enabled_before }
    }
}

impl Drop for InterruptGuard {
    fn drop(&mut self) {
        if self.enabled_before {
            crate::arch::interrupt::enable_supervisor_interrupt();
        }
    }
}

struct InterruptFreeLockedHeap<const ORDER: usize> {
    inner: LockedHeap<ORDER>,
}

impl<const ORDER: usize> InterruptFreeLockedHeap<ORDER> {
    const fn empty() -> Self {
        Self {
            inner: LockedHeap::empty(),
        }
    }

    unsafe fn init(&self, start: usize, size: usize) {
        let _guard = InterruptGuard::new();
        unsafe {
            self.inner.lock().init(start, size);
        }
    }
}

unsafe impl<const ORDER: usize> GlobalAlloc for InterruptFreeLockedHeap<ORDER> {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        let _guard = InterruptGuard::new();
        unsafe { GlobalAlloc::alloc(&self.inner, layout) }
    }

    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        let _guard = InterruptGuard::new();
        unsafe {
            GlobalAlloc::dealloc(&self.inner, ptr, layout);
        }
    }
}

#[alloc_error_handler]
pub fn handle_alloc_error(layout: core::alloc::Layout) -> ! {
    panic!("Heap allocation error, layout = {:?}", layout);
}

static mut HEAP_SPACE: [u8; KERNEL_HEAP_SIZE] = [0; KERNEL_HEAP_SIZE];

/// Publishes the statically reserved kernel heap to the global allocator.
///
/// Call this once during early boot, before code paths that can allocate while
/// device interrupts are enabled. Allocation itself masks supervisor interrupts
/// so allocator metadata cannot be re-entered from an interrupt handler.
pub fn init_heap() {
    unsafe {
        HEAP_ALLOCATOR.init(addr_of_mut!(HEAP_SPACE) as usize, KERNEL_HEAP_SIZE);
    }
}
